5.query:
timeseries requests = sum(dt.service.request.count), by:{dt.entity.service}
| fieldsAdd Service = entityName(dt.entity.service)
| filter in(Service, {"nova-mes-web", "nova-batch-service", "nova-dispensing-service"})

6.query:
timeseries `response time` = avg(dt.service.request.response_time), by:{dt.entity.service}
| fieldsAdd Service = entityName(dt.entity.service)
| filter in(Service, {"nova-mes-web", "nova-batch-service", "nova-dispensing-service"})

8.query:
fetch logs
| filter k8s.namespace.name == "nova-mes"
| makeTimeseries logs = count(), by:{loglevel}
